const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const token = $('Get OAuth Token').first().json.access_token;
const data = $('Webhook').first().json.body;

// --- Step 1: Get template binary ---
let templateBuffer;
try {
  const bin = $('Download Template').first().binary;
  if (bin && bin.data && bin.data.data) {
    templateBuffer = Buffer.from(bin.data.data, 'base64');
    console.log('Template from HTTP node: ' + templateBuffer.length + ' bytes');
  }
} catch (e) {
  console.log('Binary access failed: ' + e.message);
}

// Fallback: download directly via curl if HTTP node binary access failed
if (!templateBuffer || templateBuffer.length < 100) {
  console.log('Downloading template via curl fallback...');
  const siteId = $env.GRAPH_SITE_ID || '';
  const url = 'https://graph.microsoft.com/v1.0/sites/' + siteId +
    '/drive/root:/DAX Templates/ICP-Quarterly-Review-TEMPLATE.docx:/content';
  const tmpDl = '/tmp/tpl-' + Date.now() + '.docx';
  execFileSync('curl', ['-sL', '-o', tmpDl, '-H', 'Authorization: Bearer ' + token, url]);
  templateBuffer = fs.readFileSync(tmpDl);
  fs.unlinkSync(tmpDl);
  console.log('Template via curl: ' + templateBuffer.length + ' bytes');
}

// Validate zip signature (PK = 0x504B)
if (templateBuffer.length < 4 || templateBuffer[0] !== 0x50 || templateBuffer[1] !== 0x4B) {
  throw new Error('Not a valid docx. Size: ' + templateBuffer.length +
    ', first bytes: ' + templateBuffer.slice(0, 20).toString('hex'));
}

// --- Step 2: Unzip ---
const workDir = '/tmp/docx-' + Date.now();
const templatePath = path.join(workDir, 'template.docx');
const extractDir = path.join(workDir, 'extracted');
const outputPath = path.join(workDir, 'report.docx');

fs.mkdirSync(extractDir, { recursive: true });
fs.writeFileSync(templatePath, templateBuffer);
execFileSync('unzip', ['-o', templatePath, '-d', extractDir]);

// --- Step 3: Read and pre-process document.xml ---
const docXmlPath = path.join(extractDir, 'word', 'document.xml');
let xml = fs.readFileSync(docXmlPath, 'utf8');
console.log('document.xml: ' + xml.length + ' chars');

// Merge adjacent text runs that Word splits across XML elements.
// Word often breaks {{placeholder}} into separate <w:r> runs like:
//   <w:t>{{</w:t></w:r><w:r><w:t>clientName}}</w:t>
// This merges them back so split/join replacement can find the full token.
let mergeCount = 0;
let prev;
do {
  prev = xml;
  xml = xml.split('</w:t></w:r><w:r><w:t>').join('');
  xml = xml.split('</w:t></w:r><w:r><w:t xml:space="preserve">').join('');
} while (xml !== prev && ++mergeCount < 20);
if (mergeCount > 0) {
  console.log('Merged split runs (' + mergeCount + ' pass' + (mergeCount > 1 ? 'es' : '') + ')');
}

// Also merge runs that have formatting properties (rPr) between them.
// Pattern: </w:t></w:r><w:r><w:rPr>...</w:rPr><w:t> or <w:t xml:space=...>
let rprPrev;
do {
  rprPrev = xml;
  xml = xml.replace(/<\/w:t><\/w:r><w:r><w:rPr>[^]*?<\/w:rPr><w:t(?:\s[^>]*)?>/g, '');
} while (xml !== rprPrev);

// --- Step 4: Replace {{placeholder}} tokens ---
const fields = {
  clientName: data.clientName,
  firmName: data.firmName,
  reportPeriod: data.reportPeriod,
  reportDate: data.reportDate,
  advisorName: data.advisorName,
  meetingDate: data.meetingDate,
  meetingLocation: data.meetingLocation,
  attendees: data.attendees,
  meetingDuration: data.meetingDuration,
  discussionPoint1: data.discussionPoint1,
  discussionPoint2: data.discussionPoint2,
  discussionPoint3: data.discussionPoint3,
  advisorNotes: data.advisorNotes,
  portfolioValue: data.portfolioValue,
  ytdReturn: data.ytdReturn,
  benchmarkReturn: data.benchmarkReturn,
  vsBenchmark: data.vsBenchmark,
  goal1: data.goal1,
  goal2: data.goal2,
  goal3: data.goal3,
  goalsProgressNotes: data.goalsProgressNotes,
  action1: data.action1,
  action1Owner: data.action1Owner,
  action1Due: data.action1Due,
  action2: data.action2,
  action2Owner: data.action2Owner,
  action2Due: data.action2Due,
  action3: data.action3,
  action3Owner: data.action3Owner,
  action3Due: data.action3Due,
  nextMeetingDate: data.nextMeetingDate,
  nextMeetingAgenda: data.nextMeetingAgenda
};

let totalReplaced = 0;
for (const [key, val] of Object.entries(fields)) {
  const tag = '{{' + key + '}}';
  const count = xml.split(tag).length - 1;
  if (count > 0) {
    const safe = (val || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
    xml = xml.split(tag).join(safe);
    totalReplaced += count;
    console.log('  ' + tag + ' x' + count);
  }
}
console.log('Replaced ' + totalReplaced + ' placeholders');

// Warn about any remaining unfilled placeholders
const remaining = xml.match(/\{\{\w+\}\}/g);
if (remaining) {
  console.log('WARNING unfilled: ' + remaining.join(', '));
}

fs.writeFileSync(docXmlPath, xml);

// --- Step 5: Rezip ---
execFileSync('zip', ['-r', '-q', outputPath, '.'], { cwd: extractDir });
const outputBuffer = fs.readFileSync(outputPath);
fs.rmSync(workDir, { recursive: true, force: true });

const clientName = data.clientName || 'Unknown';
const reportPeriod = data.reportPeriod || 'Report';
const fileName = reportPeriod + '.docx';
console.log('Output: ' + outputBuffer.length + ' bytes -> DAX Reports/' + clientName + '/' + fileName);

return [{
  json: {
    clientName,
    reportPeriod,
    fileName,
    fileSize: outputBuffer.length
  },
  binary: {
    data: {
      data: outputBuffer.toString('base64'),
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      fileName
    }
  }
}];
